-- More businesses from TripAdvisor + research round 2

INSERT INTO businesses (id, name, category, description, phone, whatsapp, lat, lng, image, delivery_time, delivery_fee, min_order, rating, open_time, close_time, is_active, vertical) VALUES
-- Restaurants & Bars
('00000000-0000-0000-0000-000000000023', 'Micaela - Maximo Refinamiento', 'food', 'Italian-Latin-Seafood-Mediterranean fine dining. Best food and location in Venao. 15 reviews on TripAdvisor.', '', '', 7.4211, -80.1506, 'https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=800&q=80', '25-40', 3, 15, 4.8, 12, 22, true, 'food'),
('00000000-0000-0000-0000-000000000024', 'El Toro Mediterranean', 'food', 'Fast-casual Mediterranean. Exceptional sandwiches, fresh ingredients. Quick and delicious.', '', '', 7.4213, -80.1503, 'https://images.unsplash.com/photo-1568901346375-23c9450c58cd?w=800&q=80', '10-20', 1, 6, 4.5, 10, 21, true, 'food'),
('00000000-0000-0000-0000-000000000025', 'Venao Brewing House', 'drinks', 'Local craft brewery. Fresh beer brewed in Venao. Great spot for drinks and conversation.', '', '', 7.4215, -80.1500, 'https://images.unsplash.com/photo-1608270586620-248524c67de9?w=800&q=80', '10-20', 0, 5, 4.6, 14, 23, true, 'food'),
('00000000-0000-0000-0000-000000000026', 'Natural Venao', 'food', 'Healthy food spot. Fresh, natural ingredients. 5.0 rated on TripAdvisor. #11 of 18 restaurants.', '', '', 7.4218, -80.1502, 'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=800&q=80', '15-25', 2, 8, 5.0, 8, 18, true, 'food'),
('00000000-0000-0000-0000-000000000027', 'Coconut Grill House', 'food', 'Grill restaurant at Wao Beach Plaza. Steaks, seafood, grilled meats with ocean view.', '', '', 7.4206, -80.1512, 'https://images.unsplash.com/photo-1544025162-d76538823936?w=800&q=80', '20-35', 2, 12, 4.7, 12, 22, true, 'food'),
('00000000-0000-0000-0000-000000000028', 'Ricos Coffee', 'food', 'Coffee shop with 116 TripAdvisor reviews. The go-to caffeine spot in Venao.', '', '', 7.4214, -80.1501, 'https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?w=800&q=80', '10-15', 1, 4, 4.5, 6, 16, true, 'food'),
-- Experiences
('00000000-0000-0000-0000-0000000000eb', 'Whale Watching Tour', 'Tour', 'Humpback whale watching from Jul-Oct. 4hr boat tour, includes Isla Iguana stop. $45-65/person shared, $190 private.', '', '', 7.4200, -80.1500, 'https://images.unsplash.com/photo-1568430462989-44163eb1752f?w=800&q=80', 'On request', 0, 45, 4.9, 6, 14, true, 'experience'),
('00000000-0000-0000-0000-0000000000ec', 'Snorkeling & Diving Tour', 'Tour', 'Explore coral reefs and marine life. 30+ species. Beginner-friendly. Equipment included.', '', '', 7.4200, -80.1500, 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=800&q=80', 'On request', 0, 50, 4.7, 7, 15, true, 'experience'),
('00000000-0000-0000-0000-0000000000ed', 'Jet Ski Rental', 'Adventure', 'Jet ski rental on Pacific waters. Adrenaline rush with ocean views. Per hour or half day.', '', '', 7.4206, -80.1512, 'https://images.unsplash.com/photo-1544551763-77932aab3e1e?w=800&q=80', 'On request', 0, 60, 4.5, 8, 17, true, 'experience'),
('00000000-0000-0000-0000-0000000000ee', 'Parasailing Venao', 'Adventure', 'Parasailing along the beach. Fly high above Playa Venao with panoramic views.', '', '', 7.4206, -80.1512, 'https://images.unsplash.com/photo-1530866495561-507c83dc6de4?w=800&q=80', 'On request', 0, 70, 4.4, 9, 16, true, 'experience'),
('00000000-0000-0000-0000-0000000000ef', 'Terracotta Art Studio', 'Workshop', 'Pottery and painting workshops. Create your own art piece in a beach studio setting.', '', '', 7.4220, -80.1505, 'https://images.unsplash.com/photo-1565193566173-7a0ee3dbe261?w=800&q=80', 'On request', 0, 25, 4.8, 9, 17, true, 'experience'),
('00000000-0000-0000-0000-00000000ef01', 'Kayak & SUP Mangrove Tour', 'Tour', 'Guided kayak/paddleboard through mangroves to Isla Canas. Includes meal. Spot wildlife and turtles.', '', '', 7.4200, -80.1520, 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=800&q=80', 'On request', 0, 40, 4.7, 7, 15, true, 'experience'),
('00000000-0000-0000-0000-00000000ef02', 'Dolphin Watching Tour', 'Tour', 'Spot bottlenose and spotted dolphins in Pacific waters. Often combined with whale watching.', '', '', 7.4200, -80.1500, 'https://images.unsplash.com/photo-1568430462989-44163eb1752f?w=800&q=80', 'On request', 0, 40, 4.8, 7, 14, true, 'experience'),
('00000000-0000-0000-0000-00000000ef03', 'Waterfall Jungle Hike', 'Adventure', 'Easy half-day hike through jungle to hidden waterfall. No car needed, starts from Eco Venao area.', '', '', 7.4225, -80.1530, 'https://images.unsplash.com/photo-1432405972618-c6b0cfba1b5c?w=800&q=80', 'On request', 0, 15, 4.6, 7, 15, true, 'experience');

